section.codeblock:
routing-instances {
    EVPN-TYPE5-VXLAN-VRF {
        instance-type vrf;
            protocols {
                evpn {
                    ip-prefix-routes {
                        advertise direct-nexthop;
                        encapsulation vxlan;
                        vni 1000;
                        export EVPN-TYPE5-VXLAN-VRF-EXPORT-POLICY;
                    }
                }
            }
            interface ge-0/0/1.0;
            route-distinguisher 10.255.0.1:100;
            vrf-target target:100:100;
        }
    }
}

routing-instances {
    orange {
        instance-type vrf;
        routing-options {
            rib orange.inet6.0 {
                multipath;
            }
            multipath;
        }
        protocols {
            evpn {
                ip-prefix-routes {
                     advertise direct-nexthop;
                     encapsulation vxlan;
                     vni 10010;
                }
            }
        }
        interface enp4s0;
        route-distinguisher 1.1.1.1:4;
        vrf-target target:4:4;
     }
}
